export const getDashboardStats = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('dashboard.get_stats', req);
  log.start({ userId: (req.user as any)?.id ?? (req.user as any)?._id });
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  // --- MONTH BOUNDARIES ---
  const startOfThisMonth = new Date(today.getFullYear(), today.getMonth(), 1);
  const startOfLastMonth = new Date(today.getFullYear(), today.getMonth() - 1, 1);
  const endOfLastMonth = new Date(today.getFullYear(), today.getMonth(), 0, 23, 59, 59, 999);

  const sevenDaysLater = new Date(today);
  sevenDaysLater.setDate(today.getDate() + 7);
  sevenDaysLater.setHours(23, 59, 59, 999);

  const thirtyDaysLater = new Date(today);
  thirtyDaysLater.setDate(today.getDate() + 30);
  thirtyDaysLater.setHours(23, 59, 59, 999);

  const fortyEightHoursLater = new Date();
  fortyEightHoursLater.setHours(fortyEightHoursLater.getHours() + 48);

  // --- DATA ISOLATION ---
  const studentMatch: any = { is_deleted: false };
  const enrollmentMatch: any = {};
  const userId = (req.user as any)?.id || (req.user as any)?._id;

  let assignedStudentIds: mongoose.Types.ObjectId[] = [];
  if (req.user?.role === 'teacher' && userId) {
    assignedStudentIds = await studentRepo.getAssignedStudentIds(userId.toString());
    studentMatch._id = { $in: assignedStudentIds };
    enrollmentMatch.$or = [
      { teacher_id: new mongoose.Types.ObjectId(userId) },
      { student_id: { $in: assignedStudentIds } },
    ];
  }

  // 1. Core counts (Filtered by teacher if necessary)
  const [totalStudents, thisMonthCount, lastMonthCount] = await Promise.all([
    StudentModel.countDocuments(studentMatch),
    StudentModel.countDocuments({
      ...studentMatch,
      created_at: { $gte: startOfThisMonth },
    }),
    StudentModel.countDocuments({
      ...studentMatch,
      created_at: { $gte: startOfLastMonth, $lte: endOfLastMonth },
    }),
  ]);

  // 2. Monthly growth %
  const monthlyGrowthPercent =
    lastMonthCount > 0
      ? Math.round(((thisMonthCount - lastMonthCount) / lastMonthCount) * 100)
      : thisMonthCount > 0
        ? 100
        : 0;

  // 3. Status distribution (Aggregating from StudentModel for consistency with list)
  const statusCounts = await StudentModel.aggregate([
    { $match: studentMatch },
    {
      $group: {
        _id: { $ifNull: ['$status_detail', 'Chờ KSK'] },
        count: { $sum: 1 },
      },
    },
  ]);

  // 4. Total tuition debt
  const debtAgg = await CourseStudentModel.aggregate([
    { $match: { ...enrollmentMatch, $expr: { $lt: ['$paid_fee', '$fee'] } } },
    {
      $group: {
        _id: null,
        totalDebt: { $sum: { $subtract: ['$fee', '$paid_fee'] } },
        count: { $sum: 1 },
      },
    },
  ]);
  const totalDebtAmount = debtAgg[0]?.totalDebt ?? 0;
  const tuitionDebtCount = debtAgg[0]?.count ?? 0;

  // 5. Weekly exam count
  const examScheduleMatchWeekly: any = {
    start_time: { $gte: today, $lte: sevenDaysLater },
  };

  if (req.user?.role === 'teacher') {
    // Find IDs of all exams teacher is involved in
    // Note: assignedStudentIds is defined above at line 56
    const involvedExamIds = await mongoose
      .model('Exams')
      .find({
        $or: [
          { teacher_id: new mongoose.Types.ObjectId(userId) },
          { 'studentResults.student_id': { $in: assignedStudentIds } },
        ],
      })
      .distinct('_id')
      .exec();
    examScheduleMatchWeekly.exam_id = { $in: involvedExamIds };
  }

  const weeklyExamCount = await ExamScheduleModel.countDocuments(examScheduleMatchWeekly);

  // 6. Upcoming exams (30 days) - Robust query and formatting
  const examScheduleMatchUpcoming: any = {
    start_time: { $gte: today, $lte: thirtyDaysLater },
  };
  if (req.user?.role === 'teacher') {
    // reuse involvedExamIds logic or find again for consistency if needed
    // for performance we already have involvedExamIds if we pull it out
    const involvedExamIds = await mongoose
      .model('Exams')
      .find({
        $or: [
          { teacher_id: new mongoose.Types.ObjectId(userId) },
          { 'studentResults.student_id': { $in: assignedStudentIds } },
        ],
      })
      .distinct('_id')
      .exec();
    examScheduleMatchUpcoming.exam_id = { $in: involvedExamIds };
  }

  const rawUpcoming = await ExamScheduleModel.find(examScheduleMatchUpcoming)
    .sort({ start_time: 1 })
    .limit(5)
    .populate({
      path: 'exam_id',
      select: 'name exam_type license_category_id',
      populate: { path: 'license_category_id', select: 'name' },
    })
    .lean();

  const upcomingExams = rawUpcoming.map((e: any) => {
    const exam = e.exam_id as any;
    // Handle cases where exam_id might be a dangling reference (deleted exam)
    return {
      ...e,
      exam_id: {
        _id: exam?._id || e.exam_id || 'deleted',
        name: exam?.name || 'Kỳ thi không tên (Đã xóa)',
        exam_type: exam?.exam_type || 'sat_hach',
        license_category_id: exam?.license_category_id?.name || 'B2',
