  // 7. Latest registrations (Student Profiles)
  const rawLatest = await StudentModel.find(studentMatch)
    .sort({ created_at: -1 })
    .limit(5)
    .populate('user_id', 'first_name last_name phone email identity_card')
    .populate('license_category_id', 'name')
    .populate('region_id', 'name')
    .lean();

  const latestRegistrations = await Promise.all(
    rawLatest.map(async (st: any) => {
