    { $sort: { count: -1 } },
  ]);

  // 9. Recruiter (Sale) distribution
  const recruiterStats = await CourseStudentModel.aggregate([
    { $match: enrollmentMatch },
    {
      $lookup: {
        from: 'users',
        localField: 'sale_id',
        foreignField: '_id',
        as: 'recruiter',
      },
    },
    { $unwind: { path: '$recruiter', preserveNullAndEmptyArrays: true } },
    {
      $group: {
        _id: {
          $cond: [
            { $not: ['$sale_id'] },
            'Chưa gán',
            {
              $ifNull: [
                {
                  $concat: ['$recruiter.last_name', ' ', '$recruiter.first_name'],
                },
                'Chưa gán',
              ],
            },
          ],
        },
        count: { $sum: 1 },
      },
    },
    { $sort: { count: -1 } },
  ]);

  // 10. === URGENT TASKS GENERATOR ===
  const urgentTasks: Array<{
    type: 'debt' | 'exam' | 'dat';
    title: string;
    subTitle: string;
    value?: string;
    badge?: string;
  }> = [];

  // Top debt enrollments
  const debtStudents = await CourseStudentModel.find({
    ...enrollmentMatch,
    $expr: { $lt: ['$paid_fee', '$fee'] },
  })
    .sort({ paid_fee: 1 })
    .limit(2)
    .populate({
      path: 'student_id',
      populate: { path: 'user_id', select: 'first_name last_name' },
    });

  for (const cs of debtStudents) {
    const st = cs.student_id as any;
    const u = st?.user_id;
    const debtAmount = (cs.fee ?? 0) - (cs.paid_fee ?? 0);
    urgentTasks.push({
      type: 'debt',
      title: u ? `${u.last_name} ${u.first_name}` : 'Học viên ẩn',
      subTitle: 'Hạn đóng học phí chưa thanh toán',
      value: `-${debtAmount.toLocaleString('vi-VN')} đ`,
    });
  }

  // Exams within 48h
  const urgentExamsMatch: any = {
    start_time: { $gte: new Date(), $lte: fortyEightHoursLater },
  };
  if (req.user?.role === 'teacher') {
    const involvedExamIds = await mongoose
      .model('Exams')
      .find({
        $or: [
          { teacher_id: new mongoose.Types.ObjectId(userId) },
          { 'studentResults.student_id': { $in: assignedStudentIds } },
        ],
      })
      .distinct('_id')
      .exec();
    urgentExamsMatch.exam_id = { $in: involvedExamIds };
  }

  const urgentExams = await ExamScheduleModel.find(urgentExamsMatch)
    .sort({ start_time: 1 })
    .limit(2)
    .populate({
      path: 'exam_id',
      select: 'name license_category_id',
      populate: { path: 'license_category_id', select: 'name' },
    });

  for (const e of urgentExams) {
    const exam = e.exam_id as { name: string; license_category_id: string };
    const startDate = new Date(e.start_time);
    const dayLabel = startDate.toLocaleDateString('vi-VN', {
      weekday: 'long',
      hour: '2-digit',
      minute: '2-digit',
    });
    urgentTasks.push({
      type: 'exam',
      title: exam?.name ?? 'Kỳ thi sắp diễn ra',
      subTitle: `Khai mạc: ${dayLabel}`,
      badge: (exam?.license_category_id as any)?.name ?? 'B2',
    });
  }

  // Enrollments with incomplete DAT
  const datPendingStudents = await CourseStudentModel.find({
    ...enrollmentMatch,
    'progress_flags.dat_completed': false,
    status_detail: { $in: ['Đang học', 'Chờ thi'] },
  })
    .limit(2)
    .populate({
      path: 'student_id',
      populate: { path: 'user_id', select: 'first_name last_name' },
    })
    .populate({
      path: 'course_id',
      populate: { path: 'license_category_id', select: 'name' },
    });

  for (const cs of datPendingStudents) {
    const st = cs.student_id as any;
    const u = st?.user_id;
    const course = cs.course_id as any;
    urgentTasks.push({
      type: 'dat',
      title: u ? `${u.last_name} ${u.first_name}` : 'Học viên ẩn',
      subTitle: 'Chưa hoàn thành số giờ lái DAT',
      badge: course?.license_category_id?.name ?? 'B2',
    });
  }

  // --- Format status counts ---
  const countsMap: Record<string, number> = {
    total: totalStudents,
    tuitionDebt: tuitionDebtCount,
  };
  statusCounts.forEach((item: any) => {
    if (item._id) {
      let label = item._id;
      // Normalize legacy labels
      if (label === 'Đã xong KSK') label = 'Đã KSK';

      countsMap[label] = (countsMap[label] || 0) + item.count;
    }
  });

  // 11. Unread notification count & recent (Using new NotifyService)
  const unreadNotificationCount = await notifyService.getUnreadCount(userId);
  const recentRes = await notifyService.getByUser(userId, { page: 1, limit: 5 });
  const recentNotifications = recentRes.data;

  log.success(
    res,
    {
      counts: countsMap,
      totalDebtAmount,
      monthlyGrowthPercent,
      thisMonthCount,
      weeklyExamCount,
      urgentTasks,
      unreadNotificationCount,
      recentNotifications,
      latestRegistrations,
      upcomingExams,
      regionStats,
      recruiterStats,
    },
    'Dashboard statistics retrieved successfully',
  );
});

