import mongoose from 'mongoose';
import { CourseStudentModel, ICourseStudent, CourseStudentStatus } from '@/infrastructure/database/models/course_student.model';
import { PaymentModel } from '@/infrastructure/database/models/payment.model';
import { DatSessionModel } from '@/infrastructure/database/models/dat_session.model';
import logger from '@/infrastructure/logging/logger';
import { AppError } from '@/domain/exceptions/app-error';

/**
 * Cancel preview data structure
 */
export interface CancelPreview {
  hasPayments: boolean;
  hasDatSessions: boolean;
  datCompleted: boolean;
  warnings: string[];
  paymentCount: number;
  totalDatKm: number;
}

/**
 * CourseStudent Service
 * Handles enrollment-related business logic including soft delete (cancellation)
 */
export class CourseStudentService {
  /**
   * Get enrollment by ID with optional active-only filter
   */
  async getEnrollmentById(id: string, activeOnly = false): Promise<ICourseStudent | null> {
    const filter: any = { _id: new mongoose.Types.ObjectId(id) };
    if (activeOnly) {
      filter.status = { $ne: 'canceled' };
    }
    return await CourseStudentModel.findOne(filter);
  }

  /**
   * Cancel an enrollment (Soft Delete)
   * - Sets status to 'canceled'
   * - Records canceled_at, cancel_reason, canceled_by
   * - Does NOT delete any related records (payments, dat sessions, etc.)
   */
  async cancelEnrollment(id: string, reason: string, userId: string): Promise<ICourseStudent> {
    // 1. Find the enrollment
    const enrollment = await CourseStudentModel.findById(id);
    if (!enrollment) {
      throw new AppError('Enrollment not found', 404);
    }

    // 2. Check if already canceled
    if (enrollment.status === 'canceled') {
      throw new AppError('Enrollment đã bị hủy trước đó', 400);
    }

    // 3. Update enrollment with cancellation data
    enrollment.status = 'canceled';
    enrollment.canceled_at = new Date();
    enrollment.cancel_reason = reason;
    enrollment.canceled_by = new mongoose.Types.ObjectId(userId);

    const savedEnrollment = await enrollment.save();

    logger.info('Enrollment canceled successfully', {
      enrollmentId: id,
      reason,
      canceledBy: userId,
      studentId: enrollment.student_id,
      courseId: enrollment.course_id,
    });

    return savedEnrollment;
  }

  /**
   * Get cancel preview - check for payments and DAT sessions before cancel
   * Used by frontend to show warning dialogs before confirming cancellation
   */
  async getCancelPreview(id: string): Promise<CancelPreview> {
    // 1. Find the enrollment
    const enrollment = await CourseStudentModel.findById(id);
    if (!enrollment) {
      throw new AppError('Enrollment not found', 404);
    }

    // 2. Check if already canceled
    if (enrollment.status === 'canceled') {
      throw new AppError('Enrollment đã bị hủy trước đó', 400);
    }

    // 3. Parallel queries for payments and DAT sessions
    const enrollmentOid = new mongoose.Types.ObjectId(id);

    const [paymentCount, datSessionCount, totalDatKmResult] = await Promise.all([
      PaymentModel.countDocuments({ course_student_id: id }),
      DatSessionModel.countDocuments({ course_student_id: id }),
      DatSessionModel.aggregate([
        { $match: { course_student_id: enrollmentOid } },
        { $group: { _id: null, totalKm: { $sum: '$distance_km' } } },
      ]),
    ]);

    const totalKm = totalDatKmResult[0]?.totalKm || 0;
    const hasPayments = paymentCount > 0;
    const hasDatSessions = datSessionCount > 0;
    const datCompleted = totalKm >= 810; // DAT threshold is 810km

    // Build warnings based on findings
    const warnings: string[] = [];

    if (hasPayments) {
      warnings.push(`Đã có ${paymentCount} khoản thanh toán — sẽ được giữ lại trong lịch sử`);
    }

    if (datCompleted) {
      warnings.push(`Đã hoàn thành DAT (${totalKm}km) — tiến độ sẽ được giữ trong lịch sử`);
    }

    return {
      hasPayments,
      hasDatSessions,
      datCompleted,
      warnings,
      paymentCount,
      totalDatKm: totalKm,
    };
  }

  /**
   * Get enrollment history for a student
   * Returns active enrollment and historical (canceled/completed) enrollments
   */
  async getStudentEnrollmentHistory(studentId: string): Promise<{ active: ICourseStudent | null; history: ICourseStudent[] }> {
    const enrollments = await CourseStudentModel.find({ student_id: studentId })
      .sort({ created_at: -1 })
      .populate('course_id', 'name code');

    const active = enrollments.find((e) => e.status !== 'canceled') || null;
    const history = enrollments.filter((e) => e.status === 'canceled');

    return { active, history };
  }

  /**
   * Get all active enrollments (excludes canceled)
   * Used for queries that need only active enrollments
   */
  async getActiveEnrollments(filters = {}, page = 1, limit = 20): Promise<{ data: ICourseStudent[]; total: number }> {
    const query = { ...filters, status: { $ne: 'canceled' } };
    const skip = (page - 1) * limit;

    const [data, total] = await Promise.all([
      CourseStudentModel.find(query)
        .sort({ created_at: -1 })
        .skip(skip)
        .limit(limit)
        .populate('student_id', 'user_id license_category_id')
        .populate('course_id', 'name code'),
      CourseStudentModel.countDocuments(query),
    ]);

    return { data, total };
  }

  /**
   * Check if student can be enrolled in a new course
   * Returns true if no active enrollment exists
   */
  async canEnrollNewCourse(studentId: string, excludeEnrollmentId?: string): Promise<boolean> {
    const filter: any = { student_id: studentId, status: { $ne: 'canceled' } };
    if (excludeEnrollmentId) {
      filter._id = { $ne: new mongoose.Types.ObjectId(excludeEnrollmentId) };
    }
    const activeCount = await CourseStudentModel.countDocuments(filter);
    return activeCount === 0;
  }
}

// Export singleton instance
export const courseStudentService = new CourseStudentService();

import type {} from '../types/express.d';
import { Request, Response } from 'express';
import { CourseStudentService } from '@/application/services/course-student.service';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';
import { ctrlLogger } from '@/infrastructure/logging/controller-logger';

const courseStudentService = new CourseStudentService();

/**
 * GET /api/v1/course-students/:id
 * Get enrollment by ID
 */
export const getEnrollmentById = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('courseStudent.get_by_id', req);
  const idStr = req.params.id;
  log.start({ enrollmentId: idStr });

  const enrollment = await courseStudentService.getEnrollmentById(idStr, true);
  if (!enrollment) {
    return log.fail('not_found', res, 404, 'Enrollment not found');
  }

  log.success(res, enrollment, 'Lấy thông tin enrollment thành công');
});

/**
 * PATCH /api/v1/course-students/:id/cancel
 * Cancel an enrollment (Soft Delete)
 */
export const cancelEnrollment = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('courseStudent.cancel', req);
  const idStr = req.params.id;
  const { reason } = req.body;
  const userId = req.user?.id || req.user?._id;

  log.start({ enrollmentId: idStr, reason, userId });

  const enrollment = await courseStudentService.cancelEnrollment(idStr, reason || '', userId);

  log.success(res, enrollment, 'Đã hủy khóa học thành công');
});

/**
 * GET /api/v1/course-students/:id/cancel-preview
 * Get preview of what will be affected by cancellation
 */
export const getCancelPreview = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('courseStudent.cancel_preview', req);
  const idStr = req.params.id;

  log.start({ enrollmentId: idStr });

  const preview = await courseStudentService.getCancelPreview(idStr);

  log.success(res, { success: true, data: preview }, 'Lấy cancel preview thành công');
});

/**
 * GET /api/v1/course-students/student/:studentId
 * Get enrollment history for a student (active + canceled)
 */
export const getStudentEnrollmentHistory = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('courseStudent.student_history', req);
  const studentIdStr = req.params.studentId;

  log.start({ studentId: studentIdStr });

  const { active, history } = await courseStudentService.getStudentEnrollmentHistory(studentIdStr);

  // Format response according to SPEC API Contract 4.2
  log.success(res, {
    success: true,
    data: {
      active: active ? {
        _id: active._id,
        course_id: active.course_id,
        status: active.status,
        canceled_at: active.canceled_at,
        cancel_reason: active.cancel_reason,
        course: (active.course_id as any)?.name || null,
      } : null,
      history: history.map((h) => ({
        _id: h._id,
        course_id: h.course_id,
        status: h.status,
        canceled_at: h.canceled_at,
        cancel_reason: h.cancel_reason,
        course: (h.course_id as any)?.name || null,
      })),
    },
  }, 'Lấy lịch sử enrollment thành công');
});

/**
 * GET /api/v1/course-students
 * Get all active enrollments
 */
export const getActiveEnrollments = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('courseStudent.get_active', req);
  const { page = '1', limit = '20' } = req.query;
  const filters = { ...req.query };

  log.start({ page, limit, filters });

  const result = await courseStudentService.getActiveEnrollments(
    filters,
    parseInt(page as string, 10),
    parseInt(limit as string, 10),
  );

  log.success(res, {
    success: true,
    data: result.data,
    meta: {
      total: result.total,
      page: parseInt(page as string, 10),
      limit: parseInt(limit as string, 10),
    },
  }, 'Lấy danh sách enrollment active thành công');
});

import express from 'express';
import * as courseStudentController from '@/interface/controllers/course-student.controller';
import { validate } from '@/interface/middlewares/validation.middleware';
import { paginationMiddleware } from '@/interface/middlewares/pagination.middleware';
import { cancelEnrollmentSchema } from '@/interface/dtos/course-student.dto';

const router = express.Router();

// GET /api/v1/course-students - Get all active enrollments
router.get('/', paginationMiddleware, courseStudentController.getActiveEnrollments);

// GET /api/v1/course-students/student/:studentId - Get student enrollment history (active + canceled)
router.get('/student/:studentId', courseStudentController.getStudentEnrollmentHistory);

// GET /api/v1/course-students/:id - Get enrollment by ID
router.get('/:id', courseStudentController.getEnrollmentById);

// GET /api/v1/course-students/:id/cancel-preview - Check what will be affected by cancellation
router.get('/:id/cancel-preview', courseStudentController.getCancelPreview);

// PATCH /api/v1/course-students/:id/cancel - Cancel enrollment (Soft Delete)
router.patch('/:id/cancel', validate(cancelEnrollmentSchema), courseStudentController.cancelEnrollment);

export default router;

import { z } from 'zod';

const objectIdRegex = /^[0-9a-fA-F]{24}$/;

/**
 * Schema for cancel enrollment request
 * PATCH /api/v1/course-students/:id/cancel
 */
export const cancelEnrollmentSchema = z.object({
  body: z.object({
    reason: z
      .string()
      .min(1, 'Lý do hủy enrollment là bắt buộc')
      .max(500, 'Lý do hủy không được vượt quá 500 ký tự')
      .optional()
      .default(''),
  }),
  params: z.object({
    id: z.string().regex(objectIdRegex, 'Mã enrollment phải là ObjectId hợp lệ'),
  }),
});

/**
 * Schema for cancel preview request
 * GET /api/v1/course-students/:id/cancel-preview
 */
export const cancelPreviewParamsSchema = z.object({
  params: z.object({
    id: z.string().regex(objectIdRegex, 'Mã enrollment phải là ObjectId hợp lệ'),
  }),
});

/**
 * Schema for student enrollment history request
 * GET /api/v1/course-students/student/:studentId
 */
export const studentEnrollmentHistoryParamsSchema = z.object({
  params: z.object({
    studentId: z.string().regex(objectIdRegex, 'Mã học viên phải là ObjectId hợp lệ'),
  }),
});

export type CancelEnrollmentInput = z.infer<typeof cancelEnrollmentSchema>;
export type CancelPreviewInput = z.infer<typeof cancelPreviewParamsSchema>;
export type StudentEnrollmentHistoryInput = z.infer<typeof studentEnrollmentHistoryParamsSchema>;

