      mockDatSessionAggregate.mockResolvedValue([]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.totalDatKm).toBe(0);
      expect(result.datCompleted).toBe(false);
    });
  });

  describe('getEnrollmentById', () => {
    it('should return enrollment when found with activeOnly=false', async () => {
      const mockEnrollment = {
        _id: new mongoose.Types.ObjectId(mockEnrollmentId),
        status: 'studying',
      };
      mockCourseStudentFindOne.mockResolvedValue(mockEnrollment);

      const result = await service.getEnrollmentById(mockEnrollmentId, false);

      expect(mockCourseStudentFindOne).toHaveBeenCalledWith(
        expect.objectContaining({ _id: expect.any(mongoose.Types.ObjectId) })
      );
      expect(result).toEqual(mockEnrollment);
    });

    it('should filter out canceled enrollments when activeOnly=true', async () => {
      const mockEnrollment = {
        _id: new mongoose.Types.ObjectId(mockEnrollmentId),
        status: 'canceled',
      };
      mockCourseStudentFindOne.mockResolvedValue(mockEnrollment);

      const result = await service.getEnrollmentById(mockEnrollmentId, true);

      expect(mockCourseStudentFindOne).toHaveBeenCalledWith(
        expect.objectContaining({
          _id: expect.any(mongoose.Types.ObjectId),
          status: { $ne: 'canceled' },
        })
      );
    });

    it('should return null when enrollment not found', async () => {
      mockCourseStudentFindOne.mockResolvedValue(null);

      const result = await service.getEnrollmentById(mockEnrollmentId);

      expect(result).toBeNull();
    });
  });

  describe('canEnrollNewCourse', () => {
    const mockStudentId = '507f1f77bcf86cd799439013';

    it('should return true when no active enrollments exist', async () => {
      mockCourseStudentCountDocuments.mockResolvedValue(0);

      const result = await service.canEnrollNewCourse(mockStudentId);

      expect(result).toBe(true);
    });

    it('should return false when active enrollments exist', async () => {
      mockCourseStudentCountDocuments.mockResolvedValue(1);

      const result = await service.canEnrollNewCourse(mockStudentId);

